+fn run_test<F>(summary: &mut InteropTestSummary, name: &str, test_fn: F)
+where
+    F: FnOnce() -> Result<(), String>,
+{
+    summary.total += 1;
+    match test_fn() {
+        Ok(()) => summary.passed += 1,
+        Err(msg) => {
+            summary.failed += 1;
+            summary.failures.push(TestFailure {
+                name: name.to_string(),
+                category: "session".to_string(),
+                message: msg,
+            });
+        }
+    }
+}
