+/// Negotiate a suite from offered and supported lists.
+fn negotiate_suite<'a>(offered: &[&'a str], supported: &[&str]) -> Option<&'a str> {
+    // Find first offered suite that is also supported
+    offered
+        .iter()
+        .find(|&suite| supported.contains(suite))
+        .map(|v| v as _)
